#define BLOCK_SIZE 16

kernel void hotspot(
    int iterations,
    const global float* power,
    const global float* temp_src,
    global float* temp_dst,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    int c = get_global_id(0);
    int r = get_global_id(1);

    if (c >= col || r >= row) return;

    int idx = r * col + c;

    for (int iter = 0; iter < iterations; iter++) {
        float delta;
        float temp = temp_src[idx];

        if (r == 0 && c == 0) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + 1] - temp) / (Cap * Rx) +
                (temp_src[idx + col] - temp) / (Cap * Ry) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (r == 0 && c == col - 1) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx - 1] - temp) / (Cap * Rx) +
                (temp_src[idx + col] - temp) / (Cap * Ry) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (r == row - 1 && c == col - 1) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx - 1] - temp) / (Cap * Rx) +
                (temp_src[idx - col] - temp) / (Cap * Ry) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (r == row - 1 && c == 0) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + 1] - temp) / (Cap * Rx) +
                (temp_src[idx - col] - temp) / (Cap * Ry) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (r == 0) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + 1] + temp_src[idx - 1] - 2.0f * temp) / (Cap * Rx) +
                (temp_src[idx + col] - temp) / (Cap * Ry) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (c == col - 1) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + col] + temp_src[idx - col] - 2.0f * temp) / (Cap * Ry) +
                (temp_src[idx - 1] - temp) / (Cap * Rx) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (r == row - 1) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + 1] + temp_src[idx - 1] - 2.0f * temp) / (Cap * Rx) +
                (temp_src[idx - col] - temp) / (Cap * Ry) +
                (80.0f - temp) / (Cap * Rz));
        }
        else if (c == 0) {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + col] + temp_src[idx - col] - 2.0f * temp) / (Cap * Ry) +
                (temp_src[idx + 1] - temp) / (Cap * Rx) +
                (80.0f - temp) / (Cap * Rz));
        }
        else {
            delta = step * (power[idx] / Cap +
                (temp_src[idx + col] + temp_src[idx - col] - 2.0f * temp) / (Cap * Ry) +
                (temp_src[idx + 1] + temp_src[idx - 1] - 2.0f * temp) / (Cap * Rx) +
                (80.0f - temp) / (Cap * Rz));
        }

        temp_dst[idx] = temp + delta;
    }
}
